import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { __param } from 'tslib';
import { HttpService } from '../http.service';
import { Employee } from '../model/employee';

@Component({
  selector: 'app-empdetails',
  templateUrl: './empdetails.component.html',
  styleUrls: ['./empdetails.component.css']
})
export class EmpdetailsComponent implements OnInit {

  empobj:Employee=<Employee>{}; 

  constructor(private route:ActivatedRoute,
              private service:HttpService){}

     ngOnInit(): void {
        this.getDataFromUrl();
     }

     getDataFromUrl(){
            this.route.paramMap
            .subscribe((param:any)=>{
              // console.log(param.get("id"))
             this.getDataFromBackend(param.get("id"))
            })
     }

     getDataFromBackend(id:any){
         this.service.getParticularRecordById(id)
         .subscribe((response:any)=>{
         // console.log(response);
         this.empobj=response;
         })
     }

     OnUpdate(){

     }
}
<p>empdetails works!</p>


<br />
<div class="container">
  <div class="row">
    <div class="col">
      <div>
        <div class="card myrgb" style="width: 400px">
          <div class="card-body">
            <h4 class="card-title">{{ empobj.name }}</h4>
            <div class="card-text">
              <h5 style="text-align: center">
                <label for="">Status:</label> &nbsp;
                <span
                  [ngClass]="{
                    badge: true,
                    'rounded-pill': true,
                    'bg-success': empobj.status.toLowerCase() === 'active',
                    'bg-warning': empobj.status.toLowerCase() === 'inactive',
                    'bg-danger': empobj.status.toLowerCase() === 'suspend'
                  }"
                  style="padding: 10px"
                >
                  {{ empobj.status }}
                </span>
              </h5>
              <span> {{ empobj.mobileno }} </span><br />
              <span>
                <strong> {{ empobj.createdBy }} </strong>
              </span>
              <span> {{ empobj.department }} </span><br />
              <span> {{ empobj.status}} </span><br />
              <span> {{ empobj.emailid }} </span><br />
              <span> {{ empobj.createdBy }} </span><br />
              <span> {{ empobj.department }} </span><br />

            </div>

            <button class="btn btn-primary" (click)="OnUpdate()">
              Update Employee
            </button>
            <button routerLink="" class="btn btn-warning">Home</button>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>
